=Guest Profile:
- Name: {{ $json.guest_name }}
- Room Type: {{ $json.room_type }}
- Repeat Guest: {{ $json.repeat_guest }}
- Spend Level: {{ $json.spend_level }}
- Preferences: {{ $json.preferences }}
- Special Occasion: {{ $json.occasion }}
- Stay Phase: {{ $json.stay_phase }}

Rules:
- If stay_phase is "before_arrival": recommend room upgrade or airport pickup
- If stay_phase is "during_stay": recommend spa, dining, or experience
- Choose only ONE upsell that best matches the guest profile
- Consider spend level and preferences
- Make the offer personalized and compelling

Respond with JSON only.

parameters.jsCode:
const items = [];

for (const item of $input.all()) {
  let aiResponse = item.json.message?.content || item.json.text || '';

  aiResponse = aiResponse.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

  let upsellData;
  try {
    upsellData = JSON.parse(aiResponse);
  } catch (error) {
    upsellData = {
      upsell_type: 'Error',
      offer_message: 'Unable to generate offer',
      reason: 'AI response parsing failed'
    };
  }

  items.push({
    json: {
      guest_name: item.json.guest_name,
      email: item.json.email,
      room_type: item.json.room_type,
      stay_phase: item.json.stay_phase,
      row_number: item.json.row_number,
      upsell_type: upsellData.upsell_type || 'Unknown',
      offer_message: upsellData.offer_message || '',
      reason: upsellData.reason || ''
    },
    pairedItem: item.pairedItem
  });
}

return items;

